1	/**
2	 * Build OAuth authorize URL for a provider.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (lines 79-141).
5	 * Returns a data structure — no HTTP responses.
6	 */
7	import type { SourceType } from "@repo/app-providers";
8	import { getProvider } from "@repo/app-providers";
9	import { nanoid } from "@repo/lib";
10	import { log } from "@vendor/observability/log/next";
11	import { providerConfigs } from "../provider-configs";
12	import { storeOAuthState } from "./state";
13	
14	// ── App URL ──
15	
16	/**
17	 * App URL for redirects.
18	 * Used to validate redirect_to parameters.
19	 */
20	const appUrl = (() => {
21	  const vercelEnv = process.env.VERCEL_ENV;
22	  const vercelUrl = process.env.VERCEL_URL;
23	  const productionUrl = process.env.VERCEL_PROJECT_PRODUCTION_URL;
24	
25	  if (vercelEnv === "preview" && vercelUrl) {
26	    return `https://${vercelUrl}`;
27	  }
28	
29	  if (productionUrl) {
30	    return `https://${productionUrl}`;
31	  }
32	
33	  return "http://localhost:3024";
34	})();
35	
36	// ── Types ──
37	
38	interface AuthorizeParams {
39	  connectedBy: string;
40	  orgId: string;
41	  provider: SourceType;
42	  redirectTo?: string;
43	}
44	
45	type AuthorizeResult =
46	  | { ok: true; url: string; state: string }
47	  | { ok: false; error: string };
48	
49	// ── Build Authorize URL ──
50	
51	/**
52	 * Build an OAuth authorize URL for the given provider.
53	 *
54	 * Generates a cryptographically random state token, stores it in Redis,
55	 * and returns the authorization URL for the provider.
56	 *
57	 * @returns AuthorizeResult — either `{ ok: true, url, state }` or `{ ok: false, error }`.
58	 */
59	export async function buildAuthorizeUrl(
60	  params: AuthorizeParams
61	): Promise<AuthorizeResult> {
62	  const { provider, orgId, connectedBy, redirectTo } = params;
63	
64	  const config = providerConfigs[provider];
65	
66	  if (!config) {
67	    log.warn("[oauth/authorize] provider not configured", { provider });
68	    return { ok: false, error: "unknown_provider" };
69	  }
70	
71	  // Validate redirect_to — allowlist: "inline", localhost, or appUrl
72	  if (redirectTo && redirectTo !== "inline") {
73	    try {
74	      const url = new URL(redirectTo);
75	      if (url.hostname !== "localhost" && !redirectTo.startsWith(appUrl)) {
76	        log.warn("[oauth/authorize] invalid redirect_to (not on allowlist)", {
77	          provider,
78	          redirectTo,
79	        });
80	        return { ok: false, error: "invalid_redirect_to" };
81	      }
82	    } catch {
83	      log.warn("[oauth/authorize] invalid redirect_to (malformed URL)", {
84	        provider,
85	        redirectTo,
86	      });
87	      return { ok: false, error: "invalid_redirect_to" };
88	    }
89	  }
90	
91	  const state = nanoid();
92	
93	  // Store OAuth state in Redis (10-minute TTL) — atomic pipeline
