1	/**
2	 * Process OAuth callback — the heavyweight OAuth completion logic.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (lines 208-489).
5	 * Returns structured CallbackProcessResult instead of HTTP responses.
6	 * The Route Handler maps CallbackProcessResult to NextResponse.redirect / HTML.
7	 */
8	import { db } from "@db/app/client";
9	import { gatewayInstallations } from "@db/app/schema";
10	import type { SourceType } from "@repo/app-providers";
11	import { getProvider, providerAccountInfoSchema } from "@repo/app-providers";
12	import { and, eq } from "@vendor/db";
13	import { log } from "@vendor/observability/log/next";
14	import { providerConfigs } from "../provider-configs";
15	import { writeTokenRecord } from "../token-store";
16	import { consumeOAuthState, storeOAuthResult } from "./state";
17	
18	// ── App URL ──
19	
20	/**
21	 * App URL for redirects.
22	 */
23	const appUrl = (() => {
24	  const vercelEnv = process.env.VERCEL_ENV;
25	  const vercelUrl = process.env.VERCEL_URL;
26	  const productionUrl = process.env.VERCEL_PROJECT_PRODUCTION_URL;
27	
28	  if (vercelEnv === "preview" && vercelUrl) {
29	    return `https://${vercelUrl}`;
30	  }
31	
32	  if (productionUrl) {
33	    return `https://${productionUrl}`;
34	  }
35	
36	  return "http://localhost:3024";
37	})();
38	
39	// ── Result Types ──
40	
41	/**
42	 * Structured result from processing an OAuth callback.
43	 * The Route Handler maps this to NextResponse.redirect() or HTML response.
44	 */
45	export type CallbackProcessResult =
46	  | { kind: "redirect"; url: string }
47	  | { kind: "inline_html"; html: string; status?: number }
48	  | { kind: "error"; error: string; status: number };
49	
50	// ── Inline HTML Templates ──
51	
52	function successHtml(providerName: string): string {
53	  return `<!doctype html>
54	<html>
55	  <head><title>Connected</title></head>
56	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
57	    <div style="text-align:center">
58	      <div style="font-size:48px;margin-bottom:16px">&#10003;</div>
59	      <h1 style="margin:0 0 8px">Connected to ${providerName}!</h1>
60	      <p style="color:#666">You can close this tab and return to your terminal.</p>
61	    </div>
62	    <script>setTimeout(()=>window.close(),2000)</script>
63	  </body>
64	</html>`;
65	}
66	
67	function errorHtml(message: string): string {
68	  return `<!doctype html>
69	<html>
70	  <head><title>Connection Failed</title></head>
71	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
72	    <div style="text-align:center">
73	      <div style="font-size:48px;margin-bottom:16px">&#10007;</div>
74	      <h1 style="margin:0 0 8px">Connection Failed</h1>
75	      <p style="color:#666">${message}</p>
76	      <p style="color:#999;font-size:14px">Close this tab and try again in your terminal.</p>
77	    </div>
78	  </body>
79	</html>`;
80	}
81	
82	// ── Redirect Helpers ──
83	
84	function buildRedirectForCompletion(
85	  stateData: Record<string, string>,
86	  providerName: SourceType,
87	  opts: { reactivated?: boolean; setupAction?: string }
88	): CallbackProcessResult {
89	  const redirectTo = stateData.redirectTo;
90	
91	  if (redirectTo === "inline") {
92	    return { kind: "inline_html", html: successHtml(providerName) };
93	  }
94	
95	  if (redirectTo) {
96	    const redirectUrl = new URL(redirectTo);
97	    if (opts.reactivated) {
98	      redirectUrl.searchParams.set("reactivated", "true");
99	    }
100	    if (opts.setupAction) {
101	      redirectUrl.searchParams.set("setup_action", opts.setupAction);
102	    }
103	    return { kind: "redirect", url: redirectUrl.toString() };
104	  }
105	
106	  // Default: redirect to app (existing behavior, backwards compatible)
107	  const redirectUrl = new URL(`${appUrl}/provider/${providerName}/connected`);
108	  if (opts.reactivated) {
109	    redirectUrl.searchParams.set("reactivated", "true");
110	  }
111	  if (opts.setupAction) {
112	    redirectUrl.searchParams.set("setup_action", opts.setupAction);
113	  }
114	  return { kind: "redirect", url: redirectUrl.toString() };
115	}
116	
117	function buildRedirectForError(
118	  stateData: Record<string, string>,
119	  providerName: SourceType,
120	  message: string
121	): CallbackProcessResult {
122	  const redirectTo = stateData.redirectTo;
123	
124	  if (redirectTo === "inline") {
125	    return { kind: "inline_html", html: errorHtml(message), status: 400 };
126	  }
127	
128	  if (redirectTo) {
129	    return {
130	      kind: "redirect",
131	      url: `${redirectTo}?error=${encodeURIComponent(message)}`,
132	    };
133	  }
134	
135	  return {
136	    kind: "redirect",
137	    url: `${appUrl}/provider/${providerName}/connected?error=${encodeURIComponent(message)}`,
138	  };
139	}
140	
141	// ── Main Callback Processing ──
142	
143	export interface ProcessCallbackParams {
144	  provider: SourceType;
145	  /** All query params from the callback URL */
146	  query: Record<string, string>;
147	  /** The state token from the callback query string */
148	  state: string;
149	}
150	
151	/**
152	 * Process an OAuth callback: validate state, exchange code, upsert installation,
153	 * persist tokens, and return a structured result for the Route Handler to act on.
154	 */
155	export async function processOAuthCallback(
156	  params: ProcessCallbackParams
157	): Promise<CallbackProcessResult> {
158	  const { provider: providerName, state, query } = params;
159	
160	  const providerDef = getProvider(providerName);
161	  const config = providerConfigs[providerName];
162	
163	  if (!config) {
164	    log.warn("[oauth/callback] provider not configured", {
165	      provider: providerName,
166	    });
167	    return {
168	      kind: "error",
169	      error: "unknown_provider",
170	      status: 400,
171	    };
172	  }
173	
174	  let stateData = await consumeOAuthState(state);
175	
176	  // GitHub-initiated redirects (permission changes, reinstalls) arrive without
177	  // our state token. If state is missing but installation_id is present, look up
178	  // the existing installation to recover orgId/connectedBy.
179	  if (!stateData && providerName === "github") {
180	    const installationId = query.installation_id;
181	    if (installationId) {
182	      const existing = await db
183	        .select({
184	          orgId: gatewayInstallations.orgId,
185	          connectedBy: gatewayInstallations.connectedBy,
186	        })
187	        .from(gatewayInstallations)
188	        .where(
189	          and(
190	            eq(gatewayInstallations.provider, "github"),
191	            eq(gatewayInstallations.externalId, installationId)
192	          )
193	        )
194	        .limit(1);
195	
196	      const row = existing[0];
197	      if (row) {
198	        stateData = {
199	          provider: "github",
200	          orgId: row.orgId,
201	          connectedBy: row.connectedBy,
202	        };
203	      }
204	    }
205	  }
206	
207	  if (!stateData) {
208	    log.warn("[oauth/callback] invalid or expired state", {
209	      provider: providerName,
210	      state: state ? `${state.slice(0, 8)}...` : "empty",
211	    });
212	    return {
213	      kind: "error",
214	      error: "invalid_or_expired_state",
215	      status: 400,
216	    };
217	  }
218	
219	  if (stateData.provider !== providerName) {
220	    log.warn("[oauth/callback] state provider mismatch", {
221	      provider: providerName,
222	      stateProvider: stateData.provider,
223	    });
224	    return {
225	      kind: "error",
226	      error: "invalid_or_expired_state",
227	      status: 400,
228	    };
229	  }
230	
231	  const orgId = stateData.orgId ?? "";
232	  const connectedBy = stateData.connectedBy ?? "unknown";
233	
234	  try {
235	    const auth = providerDef.auth;
236	    if (auth.kind !== "oauth" && auth.kind !== "app-token") {
237	      log.warn("[oauth/callback] provider does not support OAuth callback", {
238	        provider: providerName,
239	        authKind: auth.kind,
240	      });
241	      return {
242	        kind: "error",
243	        error: "provider_does_not_support_oauth",
244	        status: 400,
245	      };
246	    }
247	
248	    // Pure provider logic — no DB, no framework coupling.
249	    // Both OAuthDef and AppTokenDef have processCallback — TypeScript narrows here.
250	    // SAFETY: config is providerConfigs[providerName], created by the same provider's
251	    // createConfig(). Runtime type matches TConfig; the service cannot know TConfig
252	    // statically because it serves all providers from a single Record<string, unknown>.
253	    const result = await auth.processCallback(config as never, query);
254	
255	    // Handle pending-setup: provider needs additional configuration (e.g., GitHub App request flow).
256	    // No installation to upsert — just store the setup action and redirect.
257	    if (result.status === "pending-setup") {
258	      await storeOAuthResult(state, {
259	        status: "completed",
260	        provider: providerName,
261	        setupAction: result.setupAction,
262	      });
263	
264	      log.info("[oauth/callback] pending setup, redirecting", {
265	        provider: providerName,
266	        setupAction: result.setupAction,
267	      });
268	      return buildRedirectForCompletion(stateData, providerName, {
269	        setupAction: result.setupAction,
270	      });
271	    }
272	
273	    // For all connected statuses: detect reactivation and upsert installation
274	    const existingRows = await db
275	      .select({ id: gatewayInstallations.id })
276	      .from(gatewayInstallations)
277	      .where(
278	        and(
279	          eq(gatewayInstallations.provider, providerName),
280	          eq(gatewayInstallations.externalId, result.externalId)
281	        )
282	      )
283	      .limit(1);
284	
285	    const reactivated = existingRows.length > 0;
286	
287	    // Parse through schema to validate and narrow to ProviderAccountInfo
288	    // (processCallback returns BaseProviderAccountInfo at the type level when
289	    // called through the union — schema parse gives us the concrete discriminated type)
290	    const accountInfo = providerAccountInfoSchema.parse(result.accountInfo);
291	
292	    // Upsert installation — idempotent on (provider, externalId)
293	    const rows = await db
294	      .insert(gatewayInstallations)
295	      .values({
296	        provider: providerName,
297	        externalId: result.externalId,
298	        connectedBy,
299	        orgId,
300	        status: "active",
301	        providerAccountInfo: accountInfo,
302	      })
303	      .onConflictDoUpdate({
304	        target: [
305	          gatewayInstallations.provider,
306	          gatewayInstallations.externalId,
307	        ],
308	        set: {
309	          status: "active",
310	          connectedBy,
311	          orgId,
312	          providerAccountInfo: accountInfo,
313	          updatedAt: new Date().toISOString(),
314	        },
315	      })
316	      .returning({ id: gatewayInstallations.id });
317	
318	    const installation = rows[0];
319	    if (!installation) {
320	      throw new Error("upsert_failed");
321	    }
322	
323	    // Persist OAuth tokens for statuses that include them
324	    if (
325	      result.status === "connected" ||
326	      result.status === "connected-redirect"
327	    ) {
328	      await writeTokenRecord(installation.id, result.tokens);
329	    }
330	
331	    // Store completion result in Redis for CLI polling (5-min TTL)
332	    await storeOAuthResult(state, {
333	      status: "completed",
334	      provider: providerName,
335	      ...(reactivated ? { reactivated: "true" } : {}),
336	    });
337	
338	    // Provider-specific redirect (e.g. Vercel "next" URL to complete installation lifecycle)
339	    if (result.status === "connected-redirect") {
340	      return { kind: "redirect", url: result.nextUrl };
341	    }
342	
343	    log.info("[oauth/callback] connected", {
344	      provider: providerName,
345	      reactivated,
346	    });
347	    return buildRedirectForCompletion(stateData, providerName, {
348	      reactivated,
349	    });
350	  } catch (err) {
